-- Image Renderer
local function CreateImageGroup(cache, size, startPos)
    local group = {}
    local props = { Visible = true, Transparency = 1, Position = startPos, ZIndex = 1, Size = size, Remove = function() for _, d in ipairs(cache) do d:Remove() end end }
    setmetatable(group, {
        __index = props,
        __newindex = function(t, k, v)
            if k == "Position" then
                local delta = v - props.Position
                props.Position = v
                for _, d in ipairs(cache) do d.Position = d.Position + delta end
            else
                props[k] = v
                if k == "Visible" then for _, d in ipairs(cache) do d.Visible = v end
                elseif k == "Transparency" then for _, d in ipairs(cache) do d.Transparency = v end
                elseif k == "ZIndex" then for _, d in ipairs(cache) do d.ZIndex = v end
                end
            end
        end
    })
    return group
end

local function DrawImage(data, startPos, scaleX, scaleY, zIndex, transparency)
    local cache = {}
    local palette = data.Palette
    local alphas = data.Alpha
    local x, y, w, h, c = data.X, data.Y, data.W, data.H, data.C
    for i = 1, #x do
        local rect = Drawing.new("Square")
        rect.Visible = true
        rect.Transparency = transparency * (alphas[c[i]] or 1)
        rect.ZIndex = zIndex
        rect.Filled = true
        rect.Color = palette[c[i]]
        rect.Size = Vector2.new(w[i] * scaleX, h[i] * scaleY)
        rect.Position = startPos + Vector2.new(x[i] * scaleX, y[i] * scaleY)
        table.insert(cache, rect)
    end
    return cache
end

