function speedToPercent(speed)
    local maxSpeed = 0.1
    return speed / maxSpeed
end

function percentToSpeed(percent)
    local maxSpeed = 0.1
    return percent * maxSpeed
end

task.spawn(function()
    while true do
        task.wait(1)
        local dropdownOpen = false
        if Dropdown9_Items[1] and Dropdown9_Items[1].Box then
            dropdownOpen = Dropdown9_Items[1].Box.Visible
