function hasSpawnProtection(plr)
    if not plr or not plr.Character then return false end
    local character = plr.Character
    if character:FindFirstChildOfClass("ForceField") then
        return true
    end
    return false
end

function shouldAutoVoid()
    if targetPlayer and hasSpawnProtection(targetPlayer) then
        return true, "spawn protection"
    end
    local character = player.Character
    if character then
        local humanoid = character:FindFirstChild("Humanoid")
        if humanoid and humanoid.Health < 50 then
            return true, "health below 50"
        end
    end
    return false
end

function getRandomOrbitPoint(center, radius)
    local x = (math.random() * 2 - 1) * radius
    local y = (math.random() * 2 - 1) * radius
    local z = (math.random() * 2 - 1) * radius
    return Vector3.new(center.X + x, center.Y + y, center.Z + z)
end

function teleportToTargetTorso()
    if not targetPlayer or not targetPlayer.Character then return end
    local targetPart = targetPlayer.Character:FindFirstChild("HumanoidRootPart")
    if not targetPart then
        targetPart = targetPlayer.Character:FindFirstChild("UpperTorso") or targetPlayer.Character:FindFirstChild("Torso")
    end
    if not targetPart then return end
    
    local character = player.Character
    if not character or not character:FindFirstChild("HumanoidRootPart") then return end
    
    local hrp = character.HumanoidRootPart
    hrp.Position = Vector3.new(targetPart.Position.X, targetPart.Position.Y + 3, targetPart.Position.Z)
end

function startOrbit()
    if not targetPlayer or not targetPlayer.Character or not targetPlayer.Character:FindFirstChild("HumanoidRootPart") then
        orbitEnabled = false
        Switch12_IsChecked = false
        Switch12_IndBorder.Position = Switch12.Position + Vector2.new(1, 1)
        Switch12_Ind.Position = Switch12.Position + Vector2.new(1, 1)
        return
    end
    
    teleporting = true
    lastKnownTarget = targetPlayer
    local character = player.Character
    if not character or not character:FindFirstChild("HumanoidRootPart") then
        teleporting = false
        return
    end
    
    local humanoidRootPart = character.HumanoidRootPart
    
    task.spawn(function()
        while teleporting and orbitEnabled do
            local targetValid = targetPlayer and targetPlayer.Character and targetPlayer.Character:FindFirstChild("HumanoidRootPart")
            local voidReason
            autoVoidActive, voidReason = shouldAutoVoid()
            
            if autoVoidActive then
                teleporting = false
                notify("auto-void: " .. voidReason, "void", 2)
                task.spawn(function()
                    startVoid(true)
                end)
                break
            end
            
            if targetValid then
                local targetHRP = targetPlayer.Character.HumanoidRootPart
                local targetPos = targetHRP.Position
                lastKnownTargetPosition = targetPos
                lastKnownTarget = targetPlayer
                local newPos = getRandomOrbitPoint(targetPos, Slider3_Value)
                humanoidRootPart.Position = newPos
            end
            
            if Slider25_Value <= 0 then
                task.wait()
            else
                task.wait(Slider25_Value)
            end
        end
        
        teleporting = false
    end)
end

function startVoid(isAutoVoid)
    local character = player.Character
    if not character or not character:FindFirstChild("HumanoidRootPart") then
        return
    end
    
    local humanoidRootPart = character.HumanoidRootPart
    if not isAutoVoid then
        voidStartPosition = humanoidRootPart.Position
    end
    
    task.spawn(function()
        local voidActive = true
        
        while voidActive do
            if isAutoVoid then
                local shouldStillVoid, _ = shouldAutoVoid()
                local targetValid = targetPlayer and targetPlayer.Character and targetPlayer.Character:FindFirstChild("HumanoidRootPart")
                
                if not shouldStillVoid and targetValid then
                    voidActive = false
                    autoVoidActive = false
                    notify("auto-void ended - resuming orbit", "void", 2)
                    if orbitEnabled then
                        teleporting = false
                        task.wait(0.1)
                        startOrbit()
                    end
                else
                    humanoidRootPart.Position = Vector3.new(
                        math.random(-999999, 999999),
                        math.random(0, 999999),
                        math.random(-999999, 999999)
                    )
                end
            else
                if not manualVoidEnabled then
                    voidActive = false
                    if voidStartPosition then
                        humanoidRootPart.Position = voidStartPosition
                        voidStartPosition = nil
                    end
                else
                    humanoidRootPart.Position = Vector3.new(
                        math.random(-999999, 999999),
                        math.random(0, 999999),
                        math.random(-999999, 999999)
                    )
                end
            end
            
            task.wait(0.01)
        end
    end)
end

