    if lastKnownTarget and plr.Name == lastKnownTarget.Name then
        targetPlayer = plr
        lastKnownTarget = plr
        notify("target rejoined: " .. plr.Name, "orbit", 2)
        if orbitEnabled then
            teleporting = false
            task.wait(0.1)
            startOrbit()
        end
    end
end)

